(globalThis.TURBOPACK||(globalThis.TURBOPACK=[])).push(["object"==typeof document?document.currentScript:void 0,15288,87486,12854,e=>{"use strict";var t=e.i(43476),i=e.i(75157);e.s(["Card",0,function({className:e,hover:a=!1,children:o,...s}){return(0,t.jsx)("div",{className:(0,i.cn)("glass rounded-2xl p-5",a&&"glass-hover",e),...s,children:o})},"CardTitle",0,function({className:e,children:a,...o}){return(0,t.jsx)("h3",{className:(0,i.cn)("text-sm font-semibold uppercase tracking-wider text-muted",e),...o,children:a})}],15288);let a={neutral:"bg-primary-soft text-primary",success:"bg-success/10 text-success",warning:"bg-warning/10 text-warning",danger:"bg-danger/10 text-danger",accent:"bg-accent/10 text-accent"};function o({tone:e="neutral",className:s,children:n}){return(0,t.jsx)("span",{className:(0,i.cn)("inline-flex items-center rounded-full px-2.5 py-0.5 text-[11px] font-semibold",a[e],s),children:n})}let s={easy:"success",medium:"warning",hard:"danger",gate:"accent",interview:"neutral"};e.s(["Badge",0,o,"DifficultyBadge",0,function({level:e}){return(0,t.jsx)(o,{tone:s[e],children:e.toUpperCase()})}],87486);let n=[{id:"aero-001",module:"aerospace",topic:"Compressible Flow",subtopic:"Isentropic relations",type:"nat",difficulty:"easy",companies:["ISRO","DRDO"],tags:["stagnation","isentropic"],text:"Air (γ = 1.4) flows at Mach 2. Find the ratio of stagnation temperature to static temperature, T₀/T.",answer:{value:1.8,tolerance:.01},marks:1,negative:0,estTimeSec:60,hints:["Use the isentropic stagnation temperature relation."],source:"GATE-style",solution:{steps:["T₀/T = 1 + ((γ−1)/2)·M²","= 1 + 0.2 × 2² = 1 + 0.8","T₀/T = 1.8"],concept:"Stagnation temperature ratio in isentropic compressible flow.",formula:"T₀/T = 1 + ((γ−1)/2)M²",commonMistakes:["Using (γ−1)/2 = 0.4 instead of 0.2","Forgetting to square the Mach number"],memoryTrick:"For air, T₀/T = 1 + 0.2·M². At M = 1 it is exactly 1.2.",related:"GATE AE 2015: T0/T at M = 3 (answer 2.8)"}},{id:"aero-002",module:"aerospace",topic:"Gas Dynamics",subtopic:"Normal shock",type:"mcq",difficulty:"medium",companies:["ISRO","Airbus"],tags:["normal shock","limits"],text:"As the upstream Mach number M₁ → ∞ across a normal shock in air (γ = 1.4), the downstream Mach number M₂ approaches:",options:["0","0.378","0.5","1"],correct:[1],marks:2,negative:.66,estTimeSec:90,source:"GATE-style",solution:{steps:["M₂² = [1 + ((γ−1)/2)M₁²] / [γM₁² − (γ−1)/2]","As M₁ → ∞, M₂² → (γ−1)/(2γ) = 0.4/2.8 = 0.1429","M₂ = √0.1429 ≈ 0.378"],concept:"Limiting downstream Mach number of a normal shock.",formula:"M₂(∞) = √((γ−1)/2γ)",commonMistakes:["Assuming M₂ → 0 for infinitely strong shocks"],memoryTrick:"Even the strongest shock cannot slow air below M ≈ 0.38."}},{id:"aero-003",module:"aerospace",topic:"Gas Dynamics",subtopic:"Prandtl relation",type:"mcq",difficulty:"medium",companies:["ISRO"],tags:["normal shock"],text:"For a normal shock, the Prandtl relation connects upstream velocity u₁ and downstream velocity u₂ as:",options:["u₁u₂ = a₀²","u₁u₂ = a*²","u₁/u₂ = a*²","u₁ + u₂ = 2a*"],correct:[1],marks:1,negative:.33,estTimeSec:45,source:"Anderson, Modern Compressible Flow",solution:{steps:["The Prandtl relation is u₁·u₂ = a*², where a* is the critical speed of sound.","It implies: if u₁ > a* (supersonic), then u₂ < a* (subsonic)."],concept:"Prandtl relation for normal shocks.",formula:"u₁u₂ = a*²",memoryTrick:"The shock is a 'mirror' about the critical speed a*."}},{id:"aero-004",module:"aerospace",topic:"Aerodynamics",subtopic:"Thin airfoil theory",type:"nat",difficulty:"easy",companies:["Airbus","Boeing","HAL"],tags:["lift","thin airfoil"],text:"Using thin airfoil theory, find the lift coefficient of a symmetric airfoil at an angle of attack of 5°. (Answer to 3 decimals.)",answer:{value:.548,tolerance:.01},marks:1,negative:0,estTimeSec:60,source:"GATE-style",solution:{steps:["cl = 2πα with α in radians","α = 5° = 5π/180 = 0.0873 rad","cl = 2π × 0.0873 ≈ 0.548"],concept:"Lift-curve slope of a thin symmetric airfoil is 2π per radian.",formula:"cl = 2πα",commonMistakes:["Using α in degrees — the classic trap"],memoryTrick:"≈ 0.11 per degree of angle of attack."}},{id:"aero-005",module:"aerospace",topic:"Aerodynamics",subtopic:"Finite wings",type:"nat",difficulty:"medium",companies:["Airbus","Boeing"],tags:["induced drag"],text:"A wing has CL = 0.8, aspect ratio 8 and Oswald efficiency 0.9. Compute the induced drag coefficient CDi. (3 decimals)",answer:{value:.0283,tolerance:.001},marks:2,negative:0,estTimeSec:90,source:"GATE-style",solution:{steps:["CDi = CL² / (π·e·AR)","= 0.64 / (π × 0.9 × 8) = 0.64 / 22.62","CDi ≈ 0.0283"],concept:"Induced (vortex) drag of a finite wing.",formula:"CDi = CL²/(πeAR)",commonMistakes:["Forgetting the Oswald factor e","Using CL instead of CL²"],memoryTrick:"Induced drag falls as aspect ratio grows — why gliders have long wings."}},{id:"aero-006",module:"aerospace",topic:"Aerodynamics",subtopic:"Finite wings",type:"mcq",difficulty:"medium",companies:["Airbus","HAL"],tags:["lift slope","aspect ratio"],text:"Compared with an infinite (2-D) airfoil, the lift-curve slope of a finite wing is:",options:["Higher, because tip vortices energize the flow","Lower, because downwash reduces the effective angle of attack","Identical, since lift slope is a section property","Zero for aspect ratios below 6"],correct:[1],marks:1,negative:.33,estTimeSec:45,solution:{steps:["Tip vortices induce downwash w over the wing.","Effective angle of attack αeff = α − αi drops, so the same geometric α produces less lift.","a = a₀ / (1 + a₀/(πeAR)) < a₀."],concept:"Downwash and induced angle of attack reduce finite-wing lift slope.",formula:"a = a₀/(1 + a₀/(πeAR))",memoryTrick:"Finite wing = 'leaky' lift — some effort is lost spinning tip vortices."}},{id:"aero-007",module:"aerospace",topic:"Flight Mechanics",subtopic:"Stall speed",type:"nat",difficulty:"medium",companies:["HAL","Boeing"],tags:["stall","performance"],text:"An aircraft weighs 10,000 N with wing area 16 m² and CL,max = 1.6. Taking ρ = 1.225 kg/m³, find the stall speed in m/s. (2 decimals)",answer:{value:25.25,tolerance:.3},marks:2,negative:0,estTimeSec:120,source:"GATE-style",solution:{steps:["At stall: W = ½ρV²S·CLmax","V² = 2W/(ρS·CLmax) = 20000/(1.225 × 16 × 1.6) = 637.8","Vs = √637.8 ≈ 25.25 m/s"],concept:"Slowest level-flight speed occurs at maximum lift coefficient.",formula:"Vs = √(2W/(ρSCLmax))",commonMistakes:["Forgetting the factor 2","Mixing weight (N) with mass (kg)"]}},{id:"aero-008",module:"aerospace",topic:"Flight Mechanics",subtopic:"Turning flight",type:"nat",difficulty:"easy",companies:["HAL","IAF-style"],tags:["load factor","turn"],text:"What load factor n does an aircraft experience in a level, coordinated turn at 60° bank angle?",answer:{value:2,tolerance:.01},marks:1,negative:0,estTimeSec:30,solution:{steps:["In a level turn, L cos φ = W","n = L/W = 1/cos φ = 1/cos 60° = 2"],concept:"Load factor in a coordinated level turn.",formula:"n = 1/cos φ",memoryTrick:"60° bank = 2g. Every pilot knows this one by heart."}},{id:"aero-009",module:"aerospace",topic:"Flight Mechanics",subtopic:"Static stability",type:"mcq",difficulty:"gate",companies:["HAL","Boeing","DRDO"],tags:["static margin","stability"],text:"The static margin of an aircraft is defined as the distance between the:",options:["Center of gravity and wing aerodynamic center, as a fraction of span","Neutral point and center of gravity, as a fraction of mean aerodynamic chord","Center of pressure and leading edge, as a fraction of chord","Neutral point and tail aerodynamic center, as a fraction of tail arm"],correct:[1],marks:2,negative:.66,estTimeSec:60,source:"GATE AE-style",solution:{steps:["Static margin SM = (x_NP − x_CG)/c̄.","Longitudinal static stability requires the CG ahead of the neutral point, i.e. SM > 0.","dCm/dCL = −SM, so a positive margin gives a restoring pitching moment."],concept:"Neutral point and longitudinal static stability.",formula:"SM = (x_NP − x_CG)/c̄",commonMistakes:["Confusing neutral point with center of pressure"],memoryTrick:"CG in front, plane is 'pulled straight' like a dart with nose weight."}},{id:"aero-010",module:"aerospace",topic:"Flight Mechanics",subtopic:"Dynamic modes",type:"mcq",difficulty:"gate",companies:["DRDO","HAL"],tags:["phugoid","dynamics"],text:"Which statement about the phugoid mode of an aircraft is correct?",options:["Short period, heavily damped, large angle-of-attack variation","Long period, lightly damped, nearly constant angle of attack","Long period, heavily damped, large pitch-rate oscillation","Short period, undamped, pure rolling motion"],correct:[1],marks:2,negative:.66,estTimeSec:60,source:"GATE AE-style",solution:{steps:["The phugoid is a slow exchange between kinetic and potential energy (speed ↔ altitude).","Angle of attack stays nearly constant; period is long and damping is light.","The fast, well-damped pitch oscillation at nearly constant speed is the short-period mode."],concept:"Longitudinal dynamic modes: phugoid vs short period.",memoryTrick:"Phugoid = 'porpoising' — a lazy, gliding wave through the sky."}},{id:"aero-011",module:"aerospace",topic:"Propulsion",subtopic:"Turbojet thrust",type:"nat",difficulty:"easy",companies:["HAL","ISRO"],tags:["thrust"],text:"A turbojet ingests 50 kg/s of air at a flight speed of 250 m/s and exhausts it at 600 m/s. Neglecting fuel mass flow and pressure thrust, find the net thrust in newtons.",answer:{value:17500,tolerance:100},marks:1,negative:0,estTimeSec:60,source:"GATE-style",solution:{steps:["F = ṁ(Ve − V₀)","= 50 × (600 − 250) = 50 × 350","F = 17,500 N"],concept:"Momentum thrust of an air-breathing engine.",formula:"F = ṁ(Ve − V₀)",commonMistakes:["Adding the velocities instead of subtracting"]}},{id:"aero-012",module:"aerospace",topic:"Propulsion",subtopic:"Rocket performance",type:"nat",difficulty:"medium",companies:["ISRO","DRDO"],tags:["specific impulse"],text:"A rocket engine produces 200 kN of thrust with a propellant flow rate of 80 kg/s. Compute the specific impulse in seconds (g = 9.81 m/s²). (1 decimal)",answer:{value:254.8,tolerance:2},marks:2,negative:0,estTimeSec:90,source:"ISRO-style",solution:{steps:["Isp = F/(ṁ·g)","= 200000/(80 × 9.81) = 200000/784.8","Isp ≈ 254.8 s"],concept:"Specific impulse: thrust per unit weight-flow of propellant.",formula:"Isp = F/(ṁg₀)",memoryTrick:"Isp in seconds ≈ 'how many seconds 1 kg of propellant can push with 1 kgf'."}},{id:"aero-013",module:"aerospace",topic:"Propulsion",subtopic:"Rocket equation",type:"nat",difficulty:"medium",companies:["ISRO"],tags:["delta-v","Tsiolkovsky"],text:"A rocket with effective exhaust velocity 2500 m/s has an initial-to-final mass ratio of 4. Find the ideal Δv in m/s. (nearest integer)",answer:{value:3466,tolerance:20},marks:2,negative:0,estTimeSec:90,source:"ISRO-style",solution:{steps:["Δv = Ve · ln(m₀/mf)","= 2500 × ln 4 = 2500 × 1.3863","Δv ≈ 3466 m/s"],concept:"Tsiolkovsky rocket equation.",formula:"Δv = Ve ln(m₀/mf)",commonMistakes:["Using log₁₀ instead of natural log"],memoryTrick:"ln 4 ≈ 1.386 — doubling mass ratio adds Ve·ln2 ≈ 0.693·Ve."}},{id:"aero-014",module:"aerospace",topic:"Propulsion",subtopic:"Efficiencies",type:"nat",difficulty:"medium",companies:["HAL","Airbus"],tags:["propulsive efficiency"],text:"A jet flies at V₀ with exhaust velocity Ve = 2V₀. Find the propulsive efficiency. (3 decimals)",answer:{value:.667,tolerance:.01},marks:2,negative:0,estTimeSec:60,source:"GATE-style",solution:{steps:["ηp = 2/(1 + Ve/V₀)","= 2/(1 + 2)","ηp = 2/3 ≈ 0.667"],concept:"Propulsive (Froude) efficiency of a jet.",formula:"ηp = 2/(1 + Ve/V₀)",memoryTrick:"Best efficiency when Ve ≈ V₀ — move lots of air a little (why turbofans win)."}},{id:"aero-015",module:"aerospace",topic:"Thermodynamics",subtopic:"Brayton cycle",type:"nat",difficulty:"medium",companies:["HAL","ISRO"],tags:["cycle efficiency"],text:"An ideal Brayton cycle operates at a pressure ratio of 8 with γ = 1.4. Find the thermal efficiency. (3 decimals)",answer:{value:.448,tolerance:.005},marks:2,negative:0,estTimeSec:120,source:"GATE-style",solution:{steps:["η = 1 − r^(−(γ−1)/γ)","(γ−1)/γ = 0.2857; 8^0.2857 = 1.811","η = 1 − 1/1.811 ≈ 0.448"],concept:"Ideal Brayton efficiency depends only on pressure ratio and γ.",formula:"η = 1 − (1/r)^((γ−1)/γ)",commonMistakes:["Using turbine inlet temperature — it affects net work, not ideal η"]}},{id:"aero-016",module:"aerospace",topic:"Thermodynamics",subtopic:"Carnot cycle",type:"nat",difficulty:"easy",tags:["carnot"],text:"A Carnot engine operates between 1200 K and 300 K. Find its efficiency. (2 decimals)",answer:{value:.75,tolerance:.005},marks:1,negative:0,estTimeSec:30,solution:{steps:["η = 1 − TL/TH = 1 − 300/1200","η = 0.75"],concept:"Carnot efficiency — the upper bound for any heat engine.",formula:"η = 1 − TL/TH",commonMistakes:["Using °C instead of kelvin"]}},{id:"aero-017",module:"aerospace",topic:"Gas Dynamics",subtopic:"Normal shock properties",type:"multiselect",difficulty:"gate",companies:["ISRO","DRDO"],tags:["shock","entropy"],text:"Across a stationary normal shock in a perfect gas, which of the following are TRUE? (Select all that apply.)",options:["Static pressure increases","Stagnation temperature increases","Stagnation pressure decreases","Entropy increases","Flow becomes subsonic downstream"],correct:[0,2,3,4],marks:2,negative:0,estTimeSec:90,source:"GATE AE-style",solution:{steps:["A shock is adiabatic: T₀ stays constant — option B is false.","Static pressure, temperature, density and entropy all rise.","Irreversibility destroys stagnation pressure: p₀₂ < p₀₁.","Supersonic in, subsonic out — always."],concept:"Property changes across a normal shock.",memoryTrick:"'T-naught is loyal' — stagnation temperature never changes across an adiabatic shock."}},{id:"aero-018",module:"aerospace",topic:"Gas Dynamics",subtopic:"Nozzle flow",type:"mcq",difficulty:"easy",companies:["ISRO"],tags:["area-velocity"],text:"To accelerate a supersonic flow (M > 1), the duct area must:",options:["Decrease","Increase","Stay constant","First increase, then decrease"],correct:[1],marks:1,negative:.33,estTimeSec:30,solution:{steps:["Area–velocity relation: dA/A = (M² − 1)·dV/V","For M > 1, dA and dV have the same sign: area up ⇒ speed up.","Hence rocket nozzles diverge after the throat."],concept:"Area–Mach relation for quasi-1-D isentropic flow.",formula:"dA/A = (M² − 1) dV/V",memoryTrick:"Subsonic behaves 'normally'; supersonic does the opposite."}},{id:"aero-019",module:"aerospace",topic:"Strength of Materials",subtopic:"Pressure vessels",type:"nat",difficulty:"easy",companies:["ISRO","Tata Technologies"],tags:["hoop stress"],text:"A thin cylindrical pressure vessel of radius 0.5 m and wall thickness 10 mm carries an internal pressure of 2 MPa. Find the hoop stress in MPa.",answer:{value:100,tolerance:1},marks:1,negative:0,estTimeSec:60,solution:{steps:["σ_hoop = pr/t = (2 × 10⁶ × 0.5)/0.01","σ = 100 MPa"],concept:"Membrane stresses in thin-walled cylinders.",formula:"σ_hoop = pr/t, σ_axial = pr/2t",memoryTrick:"Hoop is double the axial — cylinders split lengthwise, like a sausage."}},{id:"aero-020",module:"aerospace",topic:"Aircraft Structures",subtopic:"Buckling",type:"mcq",difficulty:"medium",companies:["Airbus","Boeing","HAL"],tags:["euler buckling"],text:"If the length of a pin-ended column is doubled, its Euler critical buckling load becomes:",options:["Half","One quarter","Double","Unchanged"],correct:[1],marks:1,negative:.33,estTimeSec:45,solution:{steps:["P_cr = π²EI/L²","P ∝ 1/L², so 2L ⇒ P/4"],concept:"Euler buckling load scales inversely with length squared.",formula:"P_cr = π²EI/(KL)²",commonMistakes:["Thinking P ∝ 1/L (linear)"]}},{id:"aero-021",module:"aerospace",topic:"Strength of Materials",subtopic:"Bending",type:"nat",difficulty:"medium",companies:["Tata Technologies","Mercedes-Benz R&D"],tags:["bending stress"],text:"A rectangular beam 100 mm wide × 200 mm deep carries a bending moment of 10 kN·m. Find the maximum bending stress in MPa.",answer:{value:15,tolerance:.3},marks:2,negative:0,estTimeSec:120,solution:{steps:["I = bh³/12 = 0.1 × 0.2³/12 = 6.667 × 10⁻⁵ m⁴","σ = My/I with y = h/2 = 0.1 m","σ = 10⁴ × 0.1 / 6.667 × 10⁻⁵ = 15 × 10⁶ Pa = 15 MPa"],concept:"Flexure formula for beams.",formula:"σ = My/I; for rectangle Z = bh²/6",altMethod:"σ = M/Z = 10⁴/(0.1 × 0.2²/6) = 15 MPa — one line with section modulus.",commonMistakes:["Using h instead of h/2 for y","mm–m unit slips"]}},{id:"aero-022",module:"aerospace",topic:"Machine Design",subtopic:"Torsion",type:"nat",difficulty:"medium",companies:["Tata Technologies","Mercedes-Benz R&D"],tags:["shaft","torsion"],text:"A solid circular shaft of diameter 50 mm transmits a torque of 1 kN·m. Find the maximum shear stress in MPa. (1 decimal)",answer:{value:40.7,tolerance:.5},marks:2,negative:0,estTimeSec:120,solution:{steps:["τ = 16T/(πd³)","= 16 × 1000/(π × 0.05³) = 16000/(3.927 × 10⁻⁴)","τ ≈ 40.7 MPa"],concept:"Torsional shear stress in a solid circular shaft.",formula:"τ = 16T/πd³",commonMistakes:["Using radius in place of diameter in 16T/πd³"],memoryTrick:"'Sixteen T over pi d cubed' — say it like a chant."}},{id:"aero-023",module:"aerospace",topic:"Strength of Materials",subtopic:"Principal stresses",type:"nat",difficulty:"easy",tags:["mohr circle"],text:"A plane-stress element has σx = 100 MPa, σy = 20 MPa and zero shear stress. Find the maximum in-plane shear stress in MPa.",answer:{value:40,tolerance:.5},marks:1,negative:0,estTimeSec:60,solution:{steps:["σx, σy are principal (no shear)","τmax = (σ₁ − σ₂)/2 = (100 − 20)/2","τmax = 40 MPa"],concept:"Maximum in-plane shear from Mohr's circle radius.",formula:"τmax = (σ₁ − σ₂)/2",memoryTrick:"Mohr's circle radius IS the max shear."}},{id:"aero-024",module:"aerospace",topic:"Aircraft Structures",subtopic:"Construction",type:"mcq",difficulty:"interview",companies:["Airbus","Boeing","HAL"],tags:["semi-monocoque"],text:"In a semi-monocoque fuselage, the primary role of the skin is to carry:",options:["Axial loads from bending","Shear and torsional loads","Concentrated engine loads","Only aerodynamic pressure"],correct:[1],marks:2,negative:.66,estTimeSec:60,source:"Interview classic (Airbus/HAL)",solution:{steps:["Stringers/longerons carry axial (bending) loads.","The thin skin is efficient in shear — it carries shear flows from torsion and transverse loads.","Frames maintain shape and distribute concentrated loads."],concept:"Load paths in semi-monocoque construction.",memoryTrick:"Skin = shear, Stringers = stretch (axial), Frames = form."}},{id:"aero-025",module:"aerospace",topic:"Control Systems",subtopic:"Routh criterion",type:"nat",difficulty:"gate",companies:["DRDO","ISRO","Qualcomm"],tags:["stability","routh"],text:"The characteristic equation of a system is s³ + 3s² + 3s + (1 + K) = 0. Find the maximum value of K for stability.",answer:{value:8,tolerance:.05},marks:2,negative:0,estTimeSec:150,source:"GATE-style",solution:{steps:["Routh array first-column conditions: all coefficients > 0 ⇒ K > −1.","s¹ row: (3×3 − (1+K))/3 > 0 ⇒ 9 > 1 + K","K < 8, so K_max = 8."],concept:"Routh–Hurwitz stability criterion.",commonMistakes:["Forgetting the K > −1 condition from the constant term"],memoryTrick:"For s³+as²+bs+c: stable iff ab > c (and all positive)."}},{id:"aero-026",module:"aerospace",topic:"Control Systems",subtopic:"Second-order response",type:"mcq",difficulty:"medium",companies:["DRDO","Texas Instruments"],tags:["damping ratio"],text:"For the system G(s) = 25/(s² + 6s + 25), the natural frequency ωn and damping ratio ζ are:",options:["ωn = 25, ζ = 6","ωn = 5, ζ = 0.6","ωn = 5, ζ = 1.2","ωn = 6, ζ = 0.5"],correct:[1],marks:1,negative:.33,estTimeSec:60,solution:{steps:["Standard form: s² + 2ζωn s + ωn²","ωn² = 25 ⇒ ωn = 5","2ζωn = 6 ⇒ ζ = 6/10 = 0.6"],concept:"Standard second-order system parameters.",formula:"s² + 2ζωn s + ωn² = 0",commonMistakes:["Forgetting the factor 2 in 2ζωn"]}},{id:"aero-027",module:"aerospace",topic:"Heat Transfer",subtopic:"Lumped capacitance",type:"mcq",difficulty:"easy",companies:["ISRO","Mercedes-Benz R&D"],tags:["biot number"],text:"The lumped-capacitance method for transient conduction is valid when:",options:["Bi > 1","Bi < 0.1","Fo < 0.1","Nu > 100"],correct:[1],marks:1,negative:.33,estTimeSec:30,solution:{steps:["Biot number Bi = hLc/k compares internal conduction resistance to external convection resistance.","Bi < 0.1 ⇒ nearly uniform internal temperature ⇒ lumped model valid."],concept:"Biot number criterion for lumped analysis.",formula:"Bi = hLc/k",memoryTrick:"Small Biot = body behaves like one 'lump' of metal."}},{id:"aero-028",module:"aerospace",topic:"Heat Transfer",subtopic:"Conduction",type:"nat",difficulty:"easy",tags:["fourier law"],text:"A plane wall of thickness 0.3 m and conductivity 1.5 W/m·K has a temperature difference of 60 K across it. Find the steady heat flux in W/m².",answer:{value:300,tolerance:2},marks:1,negative:0,estTimeSec:45,solution:{steps:["q″ = kΔT/L = 1.5 × 60/0.3","q″ = 300 W/m²"],concept:"Fourier's law across a plane wall.",formula:"q″ = kΔT/L"}},{id:"aero-029",module:"aerospace",topic:"Fluid Mechanics",subtopic:"Reynolds number",type:"nat",difficulty:"easy",companies:["Airbus"],tags:["reynolds"],text:"Air at ν = 1.5 × 10⁻⁵ m²/s flows at 30 m/s over a plate of length 2 m. Compute the Reynolds number (×10⁶, 1 decimal).",answer:{value:4,tolerance:.05},marks:1,negative:0,estTimeSec:45,solution:{steps:["Re = VL/ν = 30 × 2 / 1.5 × 10⁻⁵","Re = 4 × 10⁶ ⇒ answer 4.0"],concept:"Reynolds number: ratio of inertial to viscous forces.",formula:"Re = VL/ν",commonMistakes:["Power-of-ten slips with ν"]}},{id:"aero-030",module:"aerospace",topic:"Fluid Mechanics",subtopic:"Boundary layer",type:"nat",difficulty:"medium",companies:["Airbus","Boeing"],tags:["blasius"],text:"Using the Blasius result δ ≈ 5x/√Re_x, find the laminar boundary-layer thickness in mm at x = 1 m where Re_x = 10⁶.",answer:{value:5,tolerance:.1},marks:2,negative:0,estTimeSec:90,solution:{steps:["δ = 5x/√Re_x = 5 × 1/√10⁶","= 5/1000 m = 5 mm"],concept:"Laminar flat-plate boundary-layer growth.",formula:"δ/x = 5/√Re_x",memoryTrick:"At Re = 10⁶ the laminar BL is only ~5 mm per metre — paper-thin."}},{id:"aero-031",module:"aerospace",topic:"Engineering Mathematics",subtopic:"Linear algebra",type:"mcq",difficulty:"easy",companies:["Google","Qualcomm"],tags:["eigenvalues"],text:"The eigenvalues of the matrix [[2, 1], [1, 2]] are:",options:["1 and 3","2 and 2","0 and 4","−1 and 3"],correct:[0],marks:1,negative:.33,estTimeSec:60,solution:{steps:["det(A − λI) = (2−λ)² − 1 = 0","2 − λ = ±1 ⇒ λ = 1, 3"],concept:"Characteristic equation of a 2×2 symmetric matrix.",altMethod:"Trace = 4 = λ₁+λ₂ and det = 3 = λ₁λ₂ ⇒ {1, 3} instantly.",memoryTrick:"For [[a,b],[b,a]] the eigenvalues are always a±b."}},{id:"aero-032",module:"aerospace",topic:"Probability & Statistics",subtopic:"Basic probability",type:"nat",difficulty:"easy",companies:["Goldman Sachs","McKinsey"],tags:["dice"],text:"Two fair dice are rolled. What is the probability that their sum is 7? (4 decimals)",answer:{value:.1667,tolerance:.001},marks:1,negative:0,estTimeSec:45,solution:{steps:["Favourable: (1,6),(2,5),(3,4),(4,3),(5,2),(6,1) = 6 outcomes","P = 6/36 = 1/6 ≈ 0.1667"],concept:"Classical probability with equally likely outcomes.",memoryTrick:"7 is the most likely dice sum — exactly 1/6."}},{id:"aero-033",module:"aerospace",topic:"Numerical Methods",subtopic:"Root finding",type:"mcq",difficulty:"easy",companies:["ISRO","DRDO"],tags:["newton-raphson"],text:"The Newton–Raphson iteration for solving f(x) = 0 is:",options:["xₙ₊₁ = xₙ − f(xₙ)/f′(xₙ)","xₙ₊₁ = xₙ + f(xₙ)/f′(xₙ)","xₙ₊₁ = xₙ − f′(xₙ)/f(xₙ)","xₙ₊₁ = (xₙ + f(xₙ))/2"],correct:[0],marks:1,negative:.33,estTimeSec:30,solution:{steps:["Linearize f at xₙ: f(x) ≈ f(xₙ) + f′(xₙ)(x − xₙ)","Set to zero and solve: xₙ₊₁ = xₙ − f(xₙ)/f′(xₙ)"],concept:"Newton–Raphson uses the tangent line to chase the root.",memoryTrick:"'Minus f over f-prime' — quadratic convergence near the root."}},{id:"aero-034",module:"aerospace",topic:"Propulsion",subtopic:"Propellants",type:"mcq",difficulty:"interview",companies:["ISRO"],tags:["cryogenics"],text:"The cryogenic upper stage of ISRO's LVM3 uses which propellant combination?",options:["UDMH + N₂O₄","Liquid hydrogen + liquid oxygen","RP-1 + liquid oxygen","Solid HTPB composite"],correct:[1],marks:1,negative:.33,estTimeSec:30,source:"ISRO interview screening",solution:{steps:["Cryogenic engines (CE-20 on LVM3) burn LH₂ + LOX.","UDMH/N₂O₄ powers the hypergolic Vikas stages; solids power the S200 boosters."],concept:"Indian launch vehicle propulsion stages.",memoryTrick:"Cryo = 'cold' = liquefied gases H₂ and O₂ (20 K and 90 K)."}},{id:"aero-035",module:"aerospace",topic:"Space Mechanics",subtopic:"Circular orbits",type:"nat",difficulty:"medium",companies:["ISRO"],tags:["orbital velocity"],text:"Find the circular orbital velocity (km/s, 2 decimals) at 400 km altitude. Take Earth radius 6371 km and μ = 3.986 × 10⁵ km³/s².",answer:{value:7.67,tolerance:.05},marks:2,negative:0,estTimeSec:120,source:"ISRO-style",solution:{steps:["r = 6371 + 400 = 6771 km","v = √(μ/r) = √(398600/6771) = √58.87","v ≈ 7.67 km/s"],concept:"Circular orbit: gravity supplies exactly the centripetal force.",formula:"v = √(μ/r)",commonMistakes:["Using altitude instead of altitude + Earth radius"],memoryTrick:"LEO ≈ 7.7 km/s — about 25 times faster than an airliner."}},{id:"aero-036",module:"aerospace",topic:"Space Mechanics",subtopic:"Escape velocity",type:"mcq",difficulty:"easy",companies:["ISRO","DRDO"],tags:["escape velocity"],text:"The escape velocity from Earth's surface is approximately:",options:["7.9 km/s","9.8 km/s","11.2 km/s","15.0 km/s"],correct:[2],marks:1,negative:.33,estTimeSec:30,solution:{steps:["v_esc = √(2μ/R) = √2 × v_circular(surface)","= 1.414 × 7.9 ≈ 11.2 km/s"],concept:"Escape velocity is √2 times the surface circular velocity.",formula:"v_esc = √(2gR) = √2·v_c",memoryTrick:"7.9 to orbit, 11.2 to leave — both worth memorizing."}},{id:"aero-037",module:"aerospace",topic:"Space Mechanics",subtopic:"Kepler's laws",type:"mcq",difficulty:"easy",companies:["ISRO"],tags:["kepler"],text:"Kepler's third law relates a planet's orbital period T and semi-major axis a as:",options:["T ∝ a","T² ∝ a³","T³ ∝ a²","T ∝ 1/a²"],correct:[1],marks:1,negative:.33,estTimeSec:30,solution:{steps:["T² = (4π²/μ)·a³ for any orbit around the same central body.","Doubling the semi-major axis multiplies the period by 2^1.5 ≈ 2.83."],concept:"Harmonic law of orbital motion.",formula:"T = 2π√(a³/μ)",memoryTrick:"'Squared period, cubed distance' — T²∝a³."}},{id:"aero-038",module:"aerospace",topic:"Gas Dynamics",subtopic:"Fanno flow",type:"mcq",difficulty:"gate",companies:["ISRO","DRDO"],tags:["fanno"],text:"In Fanno flow (adiabatic flow in a constant-area duct with friction), the effect of friction is to drive the Mach number:",options:["Always toward zero","Always toward 1, from either side","Always toward infinity","Up for subsonic flow, down only beyond M = 2"],correct:[1],marks:2,negative:.66,estTimeSec:60,source:"GATE AE-style",solution:{steps:["Friction increases entropy; the Fanno line has maximum entropy at M = 1.","Subsonic flow accelerates toward 1; supersonic flow decelerates toward 1.","A duct longer than L_max forces choking and flow adjustment."],concept:"Fanno line and friction choking.",memoryTrick:"Friction and heat both 'pull' the flow to the sonic point."}},{id:"aero-039",module:"aerospace",topic:"Gas Dynamics",subtopic:"Rayleigh flow",type:"mcq",difficulty:"gate",companies:["ISRO"],tags:["rayleigh"],text:"In Rayleigh flow (frictionless, constant-area duct with heat addition), heating a subsonic flow:",options:["Decreases its Mach number","Increases its Mach number toward 1","Leaves the Mach number unchanged","Instantly makes it supersonic"],correct:[1],marks:2,negative:.66,estTimeSec:60,source:"GATE AE-style",solution:{steps:["Heat addition moves the state along the Rayleigh line toward M = 1 from both sides.","Adding more heat than the choking limit forces upstream adjustment (thermal choking).","This is why combustors are designed at low inlet Mach numbers."],concept:"Rayleigh line and thermal choking.",memoryTrick:"Combustion chambers run slow on purpose — heat pushes M toward 1."}},{id:"aero-040",module:"aerospace",topic:"Aerodynamics",subtopic:"Pressure coefficient",type:"nat",difficulty:"easy",companies:["Airbus","Boeing"],tags:["cp"],text:"For incompressible flow, what is the pressure coefficient Cp at a stagnation point?",answer:{value:1,tolerance:.001},marks:1,negative:0,estTimeSec:45,solution:{steps:["Cp = (p − p∞)/q∞ with q∞ = ½ρV∞²","At stagnation, p = p∞ + q∞ (Bernoulli) ⇒ Cp = 1."],concept:"Maximum Cp in incompressible flow is exactly 1.",formula:"Cp = 1 − (V/V∞)²",commonMistakes:["Cp can exceed 1 only in compressible flow"]}},{id:"aero-041",module:"aerospace",topic:"Flight Mechanics",subtopic:"V-n diagram",type:"mcq",difficulty:"interview",companies:["Airbus","Boeing","HAL"],tags:["load factor","v-n"],text:"Per certification requirements (e.g. CS/FAR-25), the positive limit load factor for transport aircraft is typically:",options:["+1.5","+2.5","+6.0","+9.0"],correct:[1],marks:2,negative:0,estTimeSec:45,source:"Airbus interview classic",solution:{steps:["Transport category: +2.5 / −1.0 limit load factors (fighters go to +9).","Ultimate load = 1.5 × limit load, so the structure must survive +3.75 momentarily."],concept:"Limit vs ultimate load in the V-n envelope.",memoryTrick:"Airliner 2.5, aerobatic 6, fighter 9 — and always ×1.5 for ultimate."}},{id:"aero-042",module:"aerospace",topic:"Flight Mechanics",subtopic:"Controls",type:"mcq",difficulty:"easy",companies:["HAL"],tags:["control surfaces"],text:"The primary control surfaces for roll, pitch and yaw are, respectively:",options:["Elevator, aileron, rudder","Aileron, elevator, rudder","Rudder, elevator, aileron","Aileron, rudder, elevator"],correct:[1],marks:1,negative:.33,estTimeSec:30,solution:{steps:["Ailerons (wings) → roll about the longitudinal axis.","Elevator (horizontal tail) → pitch. Rudder (vertical tail) → yaw."],concept:"Primary flight controls and body axes.",memoryTrick:"A-E-R for roll-pitch-yaw: Ailerons, Elevator, Rudder."}},{id:"aero-043",module:"aerospace",topic:"Engineering Mechanics",subtopic:"Vibrations",type:"nat",difficulty:"easy",companies:["Mercedes-Benz R&D","Tata Technologies"],tags:["natural frequency"],text:"A 1 kg mass hangs from a spring of stiffness 400 N/m. Find the natural frequency in rad/s.",answer:{value:20,tolerance:.1},marks:1,negative:0,estTimeSec:45,solution:{steps:["ωn = √(k/m) = √(400/1)","ωn = 20 rad/s (≈ 3.18 Hz)"],concept:"Undamped single-DOF natural frequency.",formula:"ωn = √(k/m); f = ωn/2π",commonMistakes:["Reporting Hz when rad/s is asked (factor 2π)"]}},{id:"aero-044",module:"aerospace",topic:"Basic Electrical",subtopic:"RC circuits",type:"nat",difficulty:"easy",companies:["Texas Instruments","Qualcomm"],tags:["time constant"],text:"An RC circuit has R = 10 kΩ and C = 100 µF. Find the time constant in seconds.",answer:{value:1,tolerance:.01},marks:1,negative:0,estTimeSec:45,solution:{steps:["τ = RC = 10 × 10³ × 100 × 10⁻⁶","τ = 1 s"],concept:"First-order RC charging/discharging time constant.",formula:"τ = RC; ~63% charge in one τ, ~99% in 5τ",commonMistakes:["Power-of-ten slips between kΩ and µF"]}},{id:"aero-045",module:"aerospace",topic:"Signals",subtopic:"Laplace transforms",type:"mcq",difficulty:"easy",companies:["DRDO","Texas Instruments"],tags:["laplace"],text:"The Laplace transform of the unit step function u(t) is:",options:["1","1/s","1/s²","e⁻ˢ"],correct:[1],marks:1,negative:.33,estTimeSec:30,solution:{steps:["L{u(t)} = ∫₀^∞ e⁻ˢᵗ dt = [−e⁻ˢᵗ/s]₀^∞ = 1/s (Re s > 0)."],concept:"Basic Laplace transform pairs.",memoryTrick:"Step 1/s, ramp 1/s², impulse 1 — the big three."}},{id:"aero-046",module:"aerospace",topic:"Manufacturing",subtopic:"Joining",type:"mcq",difficulty:"interview",companies:["HAL","Airbus","Boeing"],tags:["riveting"],text:"Aluminium airframe skins are joined mainly by riveting rather than welding because:",options:["Rivets are lighter than welds","Welding heat degrades the properties of heat-treated aluminium alloys","Welding aluminium is impossible","Rivets are aerodynamic"],correct:[1],marks:2,negative:0,estTimeSec:60,source:"HAL interview classic",solution:{steps:["Airframe alloys (2024, 7075) get strength from precipitation heat treatment.","Weld heat-affected zones lose that temper locally, and these alloys are also crack-prone when welded.","Rivets add no heat, allow inspection, and arrest crack growth at joints."],concept:"Heat-treated aluminium and joining-method selection.",memoryTrick:"You can't 'un-bake' a heat-treated alloy — so don't cook it with a torch."}},{id:"aero-047",module:"aerospace",topic:"Aircraft Structures",subtopic:"Materials",type:"mcq",difficulty:"interview",companies:["Airbus","Boeing","HAL"],tags:["aluminium alloys"],text:"In a classic metal wing, Al 7075 is preferred for the UPPER skin and Al 2024 for the LOWER skin because:",options:["7075 is cheaper than 2024","The upper skin needs 7075's higher compressive strength; the lower skin needs 2024's better fatigue and damage tolerance in tension","2024 is too heavy for the upper surface","7075 resists rain erosion better"],correct:[1],marks:2,negative:0,estTimeSec:90,source:"Airbus/Boeing interview classic",solution:{steps:["In positive-g flight the upper skin is in compression (buckling/strength critical) — 7075's higher yield wins.","The lower skin cycles in tension every flight — fatigue and crack growth dominate, favouring tougher 2024."],concept:"Matching alloy properties to the load case.",memoryTrick:"7075 = 'strong', 2024 = 'tough'. Compression up top, tension cycles below."}},{id:"cod-001",module:"coding",topic:"Searching",subtopic:"Binary search",type:"mcq",difficulty:"easy",companies:["Google","Amazon","Microsoft"],tags:["complexity"],text:"The worst-case time complexity of binary search on a sorted array of n elements is:",options:["O(1)","O(log n)","O(n)","O(n log n)"],correct:[1],marks:1,negative:.33,estTimeSec:30,solution:{steps:["Each comparison halves the search space.","After k steps the space is n/2ᵏ; it reaches 1 when k = log₂n."],concept:"Divide-and-conquer halving gives logarithmic complexity.",memoryTrick:"1 billion elements ⇒ only ~30 comparisons."}},{id:"cod-002",module:"coding",topic:"Sorting",subtopic:"Quicksort",type:"mcq",difficulty:"medium",companies:["Microsoft","Adobe","Amazon"],tags:["complexity","quicksort"],text:"Quicksort's worst-case time complexity, and a common input that triggers it with a first-element pivot, are:",options:["O(n log n); random input","O(n²); already sorted input","O(n²); input of all distinct primes","O(n log n); reverse-sorted input"],correct:[1],marks:1,negative:.33,estTimeSec:45,solution:{steps:["With a first-element pivot on sorted input, every partition is maximally unbalanced (0 and n−1).","Recurrence T(n) = T(n−1) + O(n) ⇒ O(n²)."],concept:"Pivot choice drives quicksort's balance.",commonMistakes:["Assuming quicksort is always O(n log n)"],memoryTrick:"Sorted input + naive pivot = quicksort's kryptonite. Randomize the pivot."}},{id:"cod-003",module:"coding",topic:"Hash Maps",subtopic:"Complexity",type:"mcq",difficulty:"easy",companies:["Google","Meta","Uber"],tags:["hashing"],text:"The average-case time complexity of insert and lookup in a well-designed hash table is:",options:["O(1)","O(log n)","O(n)","O(n log n)"],correct:[0],marks:1,negative:.33,estTimeSec:30,solution:{steps:["A good hash function spreads keys uniformly across buckets.","Expected chain length is the load factor α (a constant), so operations are O(1) on average.","Worst case degrades to O(n) when everything collides."],concept:"Hashing trades memory for constant-time access.",memoryTrick:"Hash = 'teleport' to the data; trees = 'binary road trip'."}},{id:"cod-004",module:"coding",topic:"Dynamic Programming",subtopic:"Kadane's algorithm",type:"nat",difficulty:"medium",companies:["Amazon","Microsoft","Goldman Sachs"],tags:["max subarray"],text:"Find the maximum subarray sum of [−2, 1, −3, 4, −1, 2, 1, −5, 4] (Kadane's algorithm).",answer:{value:6,tolerance:0},marks:2,negative:0,estTimeSec:120,source:"LeetCode #53 classic",solution:{steps:["Track best-ending-here: cur = max(x, cur + x).","Running cur: −2, 1, −2, 4, 3, 5, 6, 1, 5.","Best overall = 6, from subarray [4, −1, 2, 1]."],concept:"Kadane's algorithm: local optimum extends or restarts at each element.",formula:"cur = max(aᵢ, cur + aᵢ); best = max(best, cur)",commonMistakes:["Resetting cur to 0 fails when all elements are negative"],memoryTrick:"'Carry the baggage only if it helps.'"}},{id:"cod-005",module:"coding",topic:"Stack",subtopic:"Applications",type:"mcq",difficulty:"easy",companies:["Amazon","Adobe"],tags:["parentheses"],text:"Which data structure is the natural choice for checking balanced parentheses in an expression?",options:["Queue","Stack","Heap","Graph"],correct:[1],marks:1,negative:.33,estTimeSec:30,solution:{steps:["Push every opening bracket; on a closing bracket, pop and check it matches.","Balanced ⇔ stack is empty at the end and no mismatch occurred."],concept:"LIFO ordering mirrors the nesting of brackets.",memoryTrick:"Last opened bracket must be first closed — exactly LIFO."}},{id:"cod-006",module:"coding",topic:"Trees",subtopic:"BST properties",type:"mcq",difficulty:"easy",companies:["Microsoft","Apple"],tags:["bst","traversal"],text:"Which traversal of a binary search tree visits the keys in ascending sorted order?",options:["Preorder","Inorder","Postorder","Level order"],correct:[1],marks:1,negative:.33,estTimeSec:30,solution:{steps:["Inorder = left subtree, node, right subtree.","BST invariant (left < node < right) makes this exactly ascending order."],concept:"Inorder traversal of a BST yields sorted output.",memoryTrick:"In-order ⇒ in order."}},{id:"cod-007",module:"coding",topic:"Graphs",subtopic:"Trees as graphs",type:"nat",difficulty:"easy",companies:["Google","Uber"],tags:["tree edges"],text:"A connected acyclic graph (tree) has 50 vertices. How many edges does it have?",answer:{value:49,tolerance:0},marks:1,negative:0,estTimeSec:30,solution:{steps:["A tree on n vertices always has exactly n − 1 edges.","50 − 1 = 49."],concept:"Fundamental tree property: |E| = |V| − 1.",memoryTrick:"Every new vertex needs exactly one edge to join the family."}},{id:"cod-008",module:"coding",topic:"Bit Manipulation",subtopic:"Tricks",type:"mcq",difficulty:"medium",companies:["NVIDIA","Qualcomm","Texas Instruments"],tags:["bit tricks"],text:"For a positive integer x, the expression x & (x − 1):",options:["Sets the lowest clear bit","Clears the lowest set bit","Reverses the bits","Computes x/2 rounded down"],correct:[1],marks:1,negative:.33,estTimeSec:45,solution:{steps:["Subtracting 1 flips the lowest set bit to 0 and all bits below it to 1.","ANDing with x therefore wipes out exactly that lowest set bit.","Example: 12 (1100) & 11 (1011) = 8 (1000)."],concept:"Classic bit trick, basis of Brian Kernighan's popcount.",memoryTrick:"x & (x−1) == 0 is also the O(1) power-of-two test."}},{id:"cod-009",module:"coding",topic:"Bit Manipulation",subtopic:"Popcount",type:"nat",difficulty:"easy",companies:["NVIDIA","Qualcomm"],tags:["set bits"],text:"How many set bits (1s) are in the binary representation of 29?",answer:{value:4,tolerance:0},marks:1,negative:0,estTimeSec:45,solution:{steps:["29 = 16 + 8 + 4 + 1 = 11101₂","Set bits: 4."],concept:"Binary decomposition / population count.",altMethod:"Kernighan: 29→28→24→16→0, four iterations ⇒ 4 bits."}},{id:"cod-010",module:"coding",topic:"Dynamic Programming",subtopic:"LCS",type:"nat",difficulty:"hard",companies:["Google","Amazon","Adobe"],tags:["lcs","strings"],text:'Find the length of the Longest Common Subsequence of "ABCBDAB" and "BDCABA".',answer:{value:4,tolerance:0},marks:2,negative:0,estTimeSec:180,source:"CLRS classic",solution:{steps:["DP: L[i][j] = L[i−1][j−1] + 1 if chars match, else max(L[i−1][j], L[i][j−1]).","Filling the 7×6 table gives L = 4.",'One LCS is "BCAB" (also "BDAB").'],concept:"2-D dynamic programming over prefixes.",formula:"O(mn) time, O(mn) or O(min(m,n)) space",commonMistakes:["Confusing subsequence (gaps allowed) with substring (contiguous)"]}},{id:"cod-011",module:"coding",topic:"Recursion",subtopic:"Complexity",type:"mcq",difficulty:"easy",companies:["Microsoft","Meta"],tags:["fibonacci"],text:"Naive recursive Fibonacci (no memoization) has time complexity:",options:["O(n)","O(n²)","O(2ⁿ) (exponential)","O(log n)"],correct:[2],marks:1,negative:.33,estTimeSec:30,solution:{steps:["T(n) = T(n−1) + T(n−2) + O(1) — the call tree nearly doubles each level.","Grows as φⁿ ≈ 1.618ⁿ, i.e. exponential; memoization collapses it to O(n)."],concept:"Overlapping subproblems make naive recursion exponential.",memoryTrick:"fib(50) naive ≈ 40 billion calls; with memo, 50."}},{id:"cod-012",module:"coding",topic:"Graphs",subtopic:"Topological sort",type:"mcq",difficulty:"medium",companies:["Google","Uber","Amazon"],tags:["dag"],text:"A topological ordering of vertices exists if and only if the directed graph:",options:["Is complete","Is strongly connected","Has no directed cycle (is a DAG)","Has exactly one source vertex"],correct:[2],marks:1,negative:.33,estTimeSec:45,solution:{steps:["A cycle u→…→u makes 'u before u' impossible, so acyclicity is necessary.","Conversely every DAG has a vertex of indegree 0; peeling them off (Kahn's algorithm) builds the order."],concept:"Topological sort characterizes DAGs.",memoryTrick:"Course-prerequisite scheduling = topological sort in disguise."}},{id:"cod-013",module:"coding",topic:"Graphs",subtopic:"Shortest paths",type:"mcq",difficulty:"medium",companies:["Google","Uber"],tags:["dijkstra"],text:"Dijkstra's algorithm can fail to give correct shortest paths when the graph has:",options:["More than 10⁵ vertices","Negative edge weights","Parallel edges","Self loops"],correct:[1],marks:1,negative:.33,estTimeSec:45,solution:{steps:["Dijkstra greedily finalizes the closest unvisited vertex, assuming distances never improve later.","A negative edge can improve an already-finalized distance — the greedy invariant breaks.","Use Bellman–Ford (O(VE)) when negative weights exist."],concept:"Greedy correctness of Dijkstra requires non-negative weights.",memoryTrick:"Dijkstra never looks back — negative edges demand looking back."}},{id:"cod-014",module:"coding",topic:"Graphs",subtopic:"BFS",type:"mcq",difficulty:"easy",companies:["Meta","Amazon"],tags:["bfs"],text:"To find the shortest path (fewest edges) in an unweighted graph, the right algorithm is:",options:["DFS","BFS","Prim's algorithm","Union-Find"],correct:[1],marks:1,negative:.33,estTimeSec:30,solution:{steps:["BFS explores vertices in increasing distance layers from the source.","First time a vertex is reached is via a fewest-edge path — guaranteed by the queue order."],concept:"BFS layers = unweighted shortest distances.",memoryTrick:"BFS = ripples in a pond; DFS = a mole tunnelling."}},{id:"cod-015",module:"coding",topic:"Sliding Window",subtopic:"Fixed window",type:"nat",difficulty:"easy",companies:["Amazon","Goldman Sachs"],tags:["window sum"],text:"Find the maximum sum of any contiguous subarray of size 3 in [2, 1, 5, 1, 3, 2].",answer:{value:9,tolerance:0},marks:1,negative:0,estTimeSec:60,solution:{steps:["Windows: 2+1+5=8, 1+5+1=7, 5+1+3=9, 1+3+2=6.","Maximum = 9 for [5, 1, 3]."],concept:"Slide the window: add the entering element, drop the leaving one — O(n).",commonMistakes:["Recomputing each window from scratch (O(nk))"]}},{id:"cod-016",module:"coding",topic:"Heap",subtopic:"Complexity",type:"mcq",difficulty:"easy",companies:["Microsoft","Apple"],tags:["priority queue"],text:"In a binary min-heap with n elements, extract-min takes:",options:["O(1)","O(log n)","O(n)","O(n log n)"],correct:[1],marks:1,negative:.33,estTimeSec:30,solution:{steps:["Remove the root (the min), move the last element to the root.","Sift-down along one root-to-leaf path: height = ⌊log₂n⌋ ⇒ O(log n).","Peeking the min is O(1); extracting is O(log n)."],concept:"Heap operations cost the tree height.",memoryTrick:"Peek free, pop log."}},{id:"cod-017",module:"coding",topic:"Python",subtopic:"Slicing",type:"mcq",difficulty:"easy",companies:["Google","Goldman Sachs"],tags:["output prediction"],text:"What does print([10, 20, 30, 40][1:3]) output in Python?",options:["[20, 30]","[20, 30, 40]","[10, 20, 30]","[30, 40]"],correct:[0],marks:1,negative:.33,estTimeSec:30,solution:{steps:["Slicing a[start:stop] includes start, excludes stop.","Indices 1 and 2 ⇒ [20, 30]."],concept:"Half-open interval semantics of Python slices.",memoryTrick:"stop − start = number of elements returned."}},{id:"cod-018",module:"coding",topic:"Python",subtopic:"Gotchas",type:"mcq",difficulty:"medium",companies:["Google","Meta"],tags:["mutable default"],text:"def f(x, acc=[]):  acc.append(x); return acc\nWhat does f(1) followed by f(2) return for the second call?",options:["[2]","[1, 2]","[2, 1]","It raises TypeError"],correct:[1],marks:2,negative:.66,estTimeSec:60,solution:{steps:["Default arguments are evaluated once at function definition, not per call.","The same list object persists between calls: f(1) → [1], f(2) → [1, 2]."],concept:"Mutable default argument trap.",commonMistakes:["Expecting a fresh empty list per call"],memoryTrick:"Use acc=None then 'acc = acc or []' inside."}},{id:"cod-019",module:"coding",topic:"C++",subtopic:"STL",type:"mcq",difficulty:"medium",companies:["NVIDIA","Adobe","Qualcomm"],tags:["vector"],text:"std::vector::push_back has what time complexity, and why?",options:["Always O(1) — memory is pre-allocated","Amortized O(1) — capacity doubles on overflow","O(log n) — elements are tree-organized","O(n) — every push copies the array"],correct:[1],marks:1,negative:.33,estTimeSec:45,solution:{steps:["When size hits capacity, the vector reallocates (typically 2×) and copies all n elements.","That O(n) cost happens so rarely that averaged over n pushes it is O(1) — amortized analysis."],concept:"Amortized complexity via geometric growth.",memoryTrick:"Pay rent monthly, not per minute — occasional big cost averages out."}},{id:"cod-020",module:"coding",topic:"Java",subtopic:"Strings",type:"mcq",difficulty:"easy",companies:["Amazon","Goldman Sachs"],tags:["immutability"],text:"In Java, String objects are immutable. Repeated concatenation in a loop should therefore use:",options:["String + operator","StringBuilder","char[] only","String.intern()"],correct:[1],marks:1,negative:.33,estTimeSec:30,solution:{steps:["Each s += x creates a brand-new String and copies the old content — O(n²) over a loop.","StringBuilder mutates an internal buffer: appends are amortized O(1)."],concept:"Immutability and the cost of naive concatenation.",memoryTrick:"Loops + strings ⇒ Builder. Always."}},{id:"cod-021",module:"coding",topic:"SQL",subtopic:"Filtering",type:"mcq",difficulty:"medium",companies:["Microsoft","Uber","Goldman Sachs"],tags:["having","where"],text:"The difference between WHERE and HAVING in SQL is:",options:["WHERE filters rows before grouping; HAVING filters groups after aggregation","HAVING is faster than WHERE","WHERE works only on indexed columns","They are interchangeable"],correct:[0],marks:1,negative:.33,estTimeSec:45,solution:{steps:["Logical order: FROM → WHERE → GROUP BY → HAVING → SELECT → ORDER BY.","WHERE cannot reference aggregates like COUNT(*); HAVING can."],concept:"SQL logical query-processing order.",memoryTrick:"WHERE = bouncer at the door; HAVING = judge of the assembled groups."}},{id:"cod-022",module:"coding",topic:"SQL",subtopic:"Aggregation",type:"nat",difficulty:"easy",companies:["Uber","Goldman Sachs"],tags:["group by"],text:"Table employees has 5 rows: three in department 'A' and two in department 'B'. How many rows does this return?\nSELECT dept, COUNT(*) FROM employees GROUP BY dept;",answer:{value:2,tolerance:0},marks:1,negative:0,estTimeSec:45,solution:{steps:["GROUP BY collapses rows into one row per distinct dept value.","Distinct departments = {A, B} ⇒ 2 rows: (A, 3) and (B, 2)."],concept:"GROUP BY output cardinality = number of distinct group keys."}},{id:"cod-023",module:"coding",topic:"Graphs",subtopic:"Union-Find",type:"mcq",difficulty:"medium",companies:["Google","Amazon"],tags:["disjoint set"],text:"While adding edges one by one to an undirected graph, a cycle is detected with Union-Find when:",options:["An edge connects two vertices already in the same set","A vertex reaches degree 3","The number of edges exceeds the number of vertices","Union is called on an empty set"],correct:[0],marks:1,negative:.33,estTimeSec:45,solution:{steps:["find(u) == find(v) means u and v are already connected by some path.","Adding edge (u, v) would create a second path — a cycle.","This is exactly how Kruskal's MST algorithm skips edges."],concept:"Disjoint-set cycle detection.",memoryTrick:"Same family + new marriage = cycle."}},{id:"cod-024",module:"coding",topic:"Binary Search",subtopic:"Rotated arrays",type:"mcq",difficulty:"hard",companies:["Google","Meta","Adobe"],tags:["rotated array"],text:"To search a target in a sorted array rotated at an unknown pivot (e.g. [4,5,6,7,0,1,2]) in O(log n), the key observation is:",options:["The array must first be un-rotated in O(n)","At every mid, at least one half is properly sorted — recurse into the half that can contain the target","The pivot is always at index n/2","Two pointers from both ends meet at the target"],correct:[1],marks:2,negative:.66,estTimeSec:120,source:"LeetCode #33",solution:{steps:["Compare arr[lo] with arr[mid]: if arr[lo] ≤ arr[mid], the left half is sorted; otherwise the right half is.","Check whether the target lies inside the sorted half's range; keep that half or take the other.","Each step halves the interval ⇒ O(log n)."],concept:"Modified binary search using the sorted-half invariant.",commonMistakes:["Handling duplicates — the invariant weakens and worst case becomes O(n)"]}},{id:"cod-025",module:"coding",topic:"Sorting",subtopic:"Stability",type:"multiselect",difficulty:"medium",companies:["Microsoft","Amazon"],tags:["stable sort"],text:"Which of these sorting algorithms are stable in their standard forms? (Select all that apply.)",options:["Merge sort","Insertion sort","Heap sort","Quick sort"],correct:[0,1],marks:2,negative:0,estTimeSec:60,solution:{steps:["Stable = equal keys keep their original relative order.","Merge sort merges left-before-right on ties ⇒ stable. Insertion sort never jumps an equal element ⇒ stable.","Heap sort and quicksort move elements across long distances ⇒ unstable."],concept:"Sort stability matters when sorting by multiple keys in passes.",memoryTrick:"'MIB' — Merge, Insertion, Bubble are the stable trio."}},{id:"cod-026",module:"coding",topic:"Recursion",subtopic:"Fibonacci",type:"nat",difficulty:"easy",companies:["Adobe","Apple"],tags:["fibonacci"],text:"With F(0) = 0 and F(1) = 1, compute F(6).",answer:{value:8,tolerance:0},marks:1,negative:0,estTimeSec:45,solution:{steps:["Sequence: 0, 1, 1, 2, 3, 5, 8","F(6) = 8"],concept:"Linear recurrence evaluation.",memoryTrick:"F(6) = 8, F(10) = 55 — handy anchors for interviews."}},{id:"cod-027",module:"coding",topic:"Linked Lists",subtopic:"Two pointers",type:"mcq",difficulty:"medium",companies:["Amazon","Microsoft","Apple"],tags:["slow fast pointers"],text:"To find the middle node of a singly linked list in one pass, the standard technique is:",options:["Count nodes first, then traverse to n/2 (two passes)","Slow and fast pointers — fast moves two steps for slow's one; when fast reaches the end, slow is at the middle","Convert to an array and index n/2","Recursively split the list"],correct:[1],marks:1,negative:.33,estTimeSec:60,source:"LeetCode #876",solution:{steps:["Advance fast by 2 and slow by 1 per iteration.","When fast hits the end (or null), slow has covered exactly half the list.","The same trick detects cycles (Floyd's algorithm) when fast catches slow."],concept:"Slow/fast (tortoise-hare) pointer technique.",memoryTrick:"Hare runs twice as fast — when it finishes, the tortoise is halfway."}},{id:"cod-028",module:"coding",topic:"Queue",subtopic:"Design",type:"mcq",difficulty:"medium",companies:["Microsoft","Adobe"],tags:["two stacks"],text:"A queue implemented with two stacks (in-stack and out-stack) achieves what amortized complexity per enqueue/dequeue?",options:["O(1)","O(log n)","O(n)","O(n log n)"],correct:[0],marks:2,negative:.66,estTimeSec:90,source:"LeetCode #232",solution:{steps:["Enqueue: push onto the in-stack, O(1).","Dequeue: pop the out-stack; only when it is empty, pour the whole in-stack over (reversing order).","Each element is moved at most once ⇒ amortized O(1) per operation."],concept:"Amortized analysis: two LIFO reversals make a FIFO.",memoryTrick:"Two wrongs (reversals) make a right (order)."}},{id:"cod-029",module:"coding",topic:"Backtracking",subtopic:"N-Queens",type:"nat",difficulty:"hard",companies:["Google","Adobe"],tags:["n-queens"],text:"How many distinct solutions does the 4-Queens problem have (placing 4 non-attacking queens on a 4×4 board)?",answer:{value:2,tolerance:0},marks:2,negative:0,estTimeSec:180,source:"Classic backtracking",solution:{steps:["Backtrack column by column, pruning rows and both diagonals.","Only placements (row order) [2,4,1,3] and [3,1,4,2] survive.","They are mirror images of each other — 2 solutions."],concept:"Backtracking with constraint propagation.",memoryTrick:"N-Queens count: n=4→2, n=5→10, n=8→92."}},{id:"cod-030",module:"coding",topic:"Greedy",subtopic:"Limitations",type:"mcq",difficulty:"medium",companies:["Google","Goldman Sachs"],tags:["coin change"],text:"With coin denominations {1, 3, 4}, the greedy algorithm (always take the largest coin) fails to give minimum coins for amount 6. Greedy gives 3 coins (4+1+1); the optimum is:",options:["2 coins (3+3)","3 coins is already optimal","4 coins","1 coin"],correct:[0],marks:2,negative:.66,estTimeSec:90,solution:{steps:["Greedy: 6 → 4 + 1 + 1 = three coins.","Optimal: 3 + 3 = two coins.","Greedy is only guaranteed for 'canonical' coin systems (like standard currency); general min-coin needs DP."],concept:"Greedy-choice property does not hold for arbitrary coin systems.",memoryTrick:"{1,3,4} with 6 is THE counterexample interviewers expect you to know."}},{id:"cod-031",module:"coding",topic:"Strings",subtopic:"Sliding window",type:"nat",difficulty:"medium",companies:["Amazon","Meta","Uber"],tags:["longest substring"],text:'Find the length of the longest substring without repeating characters in "abcabcbb".',answer:{value:3,tolerance:0},marks:2,negative:0,estTimeSec:120,source:"LeetCode #3",solution:{steps:["Grow a window; on a repeat, move the left edge past the previous occurrence.","Windows: 'abc' (3), then repeats keep the best at 3 ('bca', 'cab' also length 3).","Answer: 3."],concept:"Variable-size sliding window with a last-seen map — O(n).",commonMistakes:["Restarting the window from scratch after a repeat (O(n²))"]}},{id:"cod-032",module:"coding",topic:"Arrays",subtopic:"Merging",type:"mcq",difficulty:"easy",companies:["Microsoft","Amazon"],tags:["merge"],text:"Merging two already-sorted arrays of sizes m and n into one sorted array takes:",options:["O(m + n)","O(mn)","O((m+n) log(m+n))","O(m log n)"],correct:[0],marks:1,negative:.33,estTimeSec:45,solution:{steps:["Two pointers, one per array; at each step copy the smaller front element.","Every element is touched exactly once ⇒ O(m + n).","Re-sorting the concatenation ((m+n)log(m+n)) wastes the sortedness."],concept:"The merge step of merge sort.",memoryTrick:"Sorted inputs are a gift — never throw them away by re-sorting."}},{id:"apt-001",module:"aptitude",topic:"Quantitative Aptitude",subtopic:"Percentages",type:"mcq",difficulty:"easy",companies:["McKinsey","BCG","Amazon"],tags:["successive change"],text:"A price is increased by 20% and then decreased by 20%. The net change is:",options:["No change","4% decrease","4% increase","2% decrease"],correct:[1],marks:1,negative:.33,estTimeSec:45,solution:{steps:["Net % = a + b + ab/100 = 20 − 20 + (20)(−20)/100","= −4% ⇒ 4% decrease."],concept:"Successive percentage change.",formula:"net = a + b + ab/100",memoryTrick:"Up-then-down by the same % always loses: −x²/100."}},{id:"apt-002",module:"aptitude",topic:"Quantitative Aptitude",subtopic:"Profit & Loss",type:"nat",difficulty:"easy",companies:["TCS-style","Amazon"],tags:["profit"],text:"An item bought for ₹800 is sold for ₹920. Find the profit percentage.",answer:{value:15,tolerance:.01},marks:1,negative:0,estTimeSec:45,solution:{steps:["Profit = 920 − 800 = ₹120","Profit % = 120/800 × 100 = 15%"],concept:"Profit percentage is always on cost price.",formula:"P% = (SP − CP)/CP × 100",commonMistakes:["Dividing by selling price instead of cost price"]}},{id:"apt-003",module:"aptitude",topic:"Quantitative Aptitude",subtopic:"Time & Work",type:"nat",difficulty:"medium",companies:["Microsoft","Goldman Sachs"],tags:["work rate"],text:"A completes a job in 12 days and B in 18 days. Working together, how many days do they take? (1 decimal)",answer:{value:7.2,tolerance:.05},marks:2,negative:0,estTimeSec:90,solution:{steps:["Rates: 1/12 + 1/18 = 3/36 + 2/36 = 5/36 job/day","Time = 36/5 = 7.2 days"],concept:"Work rates add when people work together.",altMethod:"LCM method: total work 36 units; A does 3/day, B does 2/day ⇒ 36/5.",memoryTrick:"Together-time = product/sum for two workers: 12×18/(12+18) = 7.2."}},{id:"apt-004",module:"aptitude",topic:"Quantitative Aptitude",subtopic:"Speed & Distance",type:"nat",difficulty:"easy",companies:["TCS-style"],tags:["trains"],text:"A 150 m long train travelling at 54 km/h crosses a pole. How many seconds does it take?",answer:{value:10,tolerance:.1},marks:1,negative:0,estTimeSec:60,solution:{steps:["54 km/h = 54 × 5/18 = 15 m/s","Time = 150/15 = 10 s"],concept:"Crossing a pole means covering the train's own length.",formula:"km/h → m/s: multiply by 5/18",memoryTrick:"×5/18 to shrink to m/s; ×18/5 to grow back."}},{id:"apt-005",module:"aptitude",topic:"Quantitative Aptitude",subtopic:"Compound Interest",type:"nat",difficulty:"medium",companies:["Goldman Sachs","BCG"],tags:["interest"],text:"Find the compound interest (in ₹) on ₹10,000 at 10% per annum for 2 years, compounded annually.",answer:{value:2100,tolerance:1},marks:2,negative:0,estTimeSec:90,solution:{steps:["Amount = 10000 × 1.1² = 12,100","CI = 12,100 − 10,000 = ₹2,100"],concept:"Compound interest grows geometrically.",formula:"A = P(1 + r/100)ⁿ",altMethod:"CI for 2 yrs = SI + interest-on-interest = 2000 + 100 = 2100."}},{id:"apt-006",module:"aptitude",topic:"Quantitative Aptitude",subtopic:"Ratio & Proportion",type:"nat",difficulty:"easy",tags:["ratio"],text:"₹1,200 is divided among three people in the ratio 2 : 3 : 5. Find the largest share in ₹.",answer:{value:600,tolerance:0},marks:1,negative:0,estTimeSec:45,solution:{steps:["Total parts = 2 + 3 + 5 = 10","Largest = 5/10 × 1200 = ₹600"],concept:"Ratio shares are fractions of the total parts."}},{id:"apt-007",module:"aptitude",topic:"Quantitative Aptitude",subtopic:"Permutations",type:"nat",difficulty:"medium",companies:["Google","Goldman Sachs"],tags:["arrangements"],text:"In how many distinct ways can the letters of the word APPLE be arranged?",answer:{value:60,tolerance:0},marks:2,negative:0,estTimeSec:60,solution:{steps:["5 letters with P repeated twice","Ways = 5!/2! = 120/2 = 60"],concept:"Permutations with repeated objects.",formula:"n!/(p₁!·p₂!…)",commonMistakes:["Forgetting to divide by 2! for the repeated P"]}},{id:"apt-008",module:"aptitude",topic:"Quantitative Aptitude",subtopic:"Probability",type:"nat",difficulty:"easy",companies:["McKinsey","Goldman Sachs"],tags:["probability"],text:"A bag has 3 red and 5 blue balls. One ball is drawn at random. What is the probability it is red? (3 decimals)",answer:{value:.375,tolerance:.001},marks:1,negative:0,estTimeSec:30,solution:{steps:["P(red) = 3/(3+5) = 3/8 = 0.375"],concept:"Probability = favourable/total for equally likely outcomes."}},{id:"apt-009",module:"aptitude",topic:"Quantitative Aptitude",subtopic:"Averages",type:"nat",difficulty:"medium",companies:["TCS-style","BCG"],tags:["averages"],text:"The average of 5 numbers is 40. When one number is removed, the average of the rest becomes 35. Find the removed number.",answer:{value:60,tolerance:0},marks:2,negative:0,estTimeSec:90,solution:{steps:["Total of 5 = 200; total of remaining 4 = 140","Removed = 200 − 140 = 60"],concept:"Work with totals, not averages.",memoryTrick:"Removed = old avg + (drop in avg × remaining count) = 40 + 5×4 = 60."}},{id:"apt-010",module:"aptitude",topic:"Quantitative Aptitude",subtopic:"Ages",type:"nat",difficulty:"medium",tags:["ages"],text:"A father is four times as old as his son. In 20 years he will be twice as old. Find the father's present age in years.",answer:{value:40,tolerance:0},marks:2,negative:0,estTimeSec:90,solution:{steps:["Let son = x, father = 4x","4x + 20 = 2(x + 20) ⇒ 2x = 20 ⇒ x = 10","Father = 40 years"],concept:"Linear equations from age relations.",commonMistakes:["Applying the 'twice' condition to present ages"]}},{id:"apt-011",module:"aptitude",topic:"Logical Reasoning",subtopic:"Number series",type:"nat",difficulty:"easy",companies:["TCS-style","Adobe"],tags:["series"],text:"Find the next term: 2, 6, 12, 20, 30, ?",answer:{value:42,tolerance:0},marks:1,negative:0,estTimeSec:60,solution:{steps:["Differences: 4, 6, 8, 10 → next difference 12","30 + 12 = 42. (Pattern: n² + n.)"],concept:"Second-difference (quadratic) series.",memoryTrick:"2,6,12,20… = products 1×2, 2×3, 3×4, 4×5…"}},{id:"apt-012",module:"aptitude",topic:"Logical Reasoning",subtopic:"Letter series",type:"mcq",difficulty:"medium",tags:["series"],text:"What comes next in the series: J, F, M, A, M, J, J, A, S, O, N, ?",options:["D","P","T","Z"],correct:[0],marks:1,negative:.33,estTimeSec:60,solution:{steps:["These are initials of the months: January, February, March…","After November comes December ⇒ D."],concept:"Lateral-thinking series — look beyond alphabet arithmetic.",memoryTrick:"If letter gaps look random, try months, days or planets."}},{id:"apt-013",module:"aptitude",topic:"Logical Reasoning",subtopic:"Coding-Decoding",type:"mcq",difficulty:"easy",companies:["TCS-style"],tags:["coding"],text:"In a certain code, CAT is written as FDW (each letter +3). How is DOG written?",options:["GRJ","GQJ","FRI","HSK"],correct:[0],marks:1,negative:.33,estTimeSec:45,solution:{steps:["D+3 = G, O+3 = R, G+3 = J","DOG → GRJ"],concept:"Fixed-shift letter coding (Caesar cipher).",memoryTrick:"Write alphabet positions 1-26 in the margin during tests."}},{id:"apt-014",module:"aptitude",topic:"Logical Reasoning",subtopic:"Blood relations",type:"mcq",difficulty:"medium",tags:["relations"],text:'Pointing to a man, Sita says, "His mother is the only daughter of my mother." How is Sita related to the man?',options:["Aunt","Mother","Sister","Grandmother"],correct:[1],marks:2,negative:.66,estTimeSec:90,solution:{steps:["'Only daughter of my mother' = Sita herself.","So the man's mother is Sita ⇒ Sita is his mother."],concept:"Resolve the self-reference first in blood-relation puzzles.",memoryTrick:"'Only daughter/son of my parents' almost always means the speaker."}},{id:"apt-015",module:"aptitude",topic:"Logical Reasoning",subtopic:"Syllogisms",type:"mcq",difficulty:"medium",companies:["McKinsey","BCG"],tags:["syllogism"],text:"Statements: All roses are flowers. Some flowers fade quickly.\nConclusion: Some roses fade quickly.\nThe conclusion is:",options:["Definitely true","Definitely false","Does not follow (cannot be determined)","True only in summer"],correct:[2],marks:2,negative:.66,estTimeSec:90,solution:{steps:["The quickly-fading flowers may be entirely non-roses.","Venn diagram: 'some flowers' need not intersect the rose circle ⇒ conclusion does not follow."],concept:"'Some A are B' + 'All C are A' proves nothing about C ∩ B.",memoryTrick:"Draw the Venn where the conclusion fails — if you can, it doesn't follow."}},{id:"apt-016",module:"aptitude",topic:"Logical Reasoning",subtopic:"Clocks",type:"nat",difficulty:"medium",tags:["clock angle"],text:"Find the angle (in degrees) between the hour and minute hands at 3:30.",answer:{value:75,tolerance:.1},marks:2,negative:0,estTimeSec:90,solution:{steps:["Angle = |30H − 5.5M| = |30×3 − 5.5×30|","= |90 − 165| = 75°"],concept:"Relative angular speed of clock hands.",formula:"θ = |30H − 5.5M|",memoryTrick:"Minute hand: 6°/min; hour hand: 0.5°/min ⇒ gap closes at 5.5°/min."}},{id:"apt-017",module:"aptitude",topic:"Logical Reasoning",subtopic:"Directions",type:"nat",difficulty:"easy",tags:["displacement"],text:"A person walks 3 km north, then 4 km east. How far (in km) is he from the start?",answer:{value:5,tolerance:.01},marks:1,negative:0,estTimeSec:45,solution:{steps:["Displacement = √(3² + 4²) = √25 = 5 km"],concept:"Pythagorean displacement.",memoryTrick:"3-4-5 is the most common triple in direction problems."}},{id:"apt-018",module:"aptitude",topic:"Analytical Reasoning",subtopic:"Seating arrangement",type:"mcq",difficulty:"medium",companies:["McKinsey","Microsoft"],tags:["arrangement"],text:"Five people A, B, C, D, E sit in a row. C sits exactly in the middle, A is immediately to the left of C, and B sits at the extreme right. Who sits at the 2nd position from the left?",options:["A","D","E","Cannot be determined"],correct:[0],marks:2,negative:.66,estTimeSec:120,solution:{steps:["Positions 1-5. C is at 3; A is at 2 (immediately left of C); B is at 5.","D and E fill 1 and 4 in either order — but position 2 is fixed: A."],concept:"Anchor fixed constraints first, then place the rest.",memoryTrick:"Answer questions about *fixed* seats even when others float."}},{id:"apt-019",module:"aptitude",topic:"Data Interpretation",subtopic:"Growth",type:"nat",difficulty:"easy",companies:["BCG","Goldman Sachs"],tags:["percentage growth"],text:"A company's sales (₹ lakh): 2021 → 120, 2022 → 150, 2023 → 180. Find the percentage growth from 2021 to 2023.",answer:{value:50,tolerance:.1},marks:1,negative:0,estTimeSec:60,solution:{steps:["Growth = (180 − 120)/120 × 100 = 50%"],concept:"Percentage change relative to the base year.",commonMistakes:["Adding year-on-year growth rates (25% + 20% ≠ 50% in general)"]}},{id:"apt-020",module:"aptitude",topic:"Data Interpretation",subtopic:"Shares",type:"nat",difficulty:"easy",tags:["ratio"],text:"Using the same data (120, 150, 180 ₹ lakh for 2021-23), what percentage of total three-year sales came in 2022? (2 decimals)",answer:{value:33.33,tolerance:.5},marks:1,negative:0,estTimeSec:60,solution:{steps:["Total = 450","2022 share = 150/450 × 100 = 33.33%"],concept:"Component percentage of an aggregate."}},{id:"apt-021",module:"aptitude",topic:"Verbal Ability",subtopic:"Vocabulary",type:"mcq",difficulty:"easy",companies:["McKinsey","Deloitte-style"],tags:["synonym"],text:"Choose the word closest in meaning to EPHEMERAL:",options:["Eternal","Short-lived","Beautiful","Dangerous"],correct:[1],marks:1,negative:.33,estTimeSec:30,solution:{steps:["Ephemeral = lasting for a very short time (Greek 'ephemeros' = for a day)."],concept:"High-frequency GRE/CAT vocabulary.",memoryTrick:"E-FEMUR-al: a mayfly's femur — gone in a day."}},{id:"apt-022",module:"aptitude",topic:"Verbal Ability",subtopic:"Vocabulary",type:"mcq",difficulty:"medium",tags:["antonym"],text:"Choose the word most nearly OPPOSITE to CANDID:",options:["Frank","Evasive","Blunt","Honest"],correct:[1],marks:1,negative:.33,estTimeSec:30,solution:{steps:["Candid = open, frank, honest.","Opposite = evasive (avoiding directness). Frank, blunt, honest are synonyms — classic traps."],concept:"Antonym questions bait you with synonyms.",memoryTrick:"Candid camera = catching the unguarded truth."}},{id:"apt-023",module:"aptitude",topic:"English Grammar",subtopic:"Subject-verb agreement",type:"mcq",difficulty:"easy",tags:["grammar"],text:'Spot the error: "Each of the students (A) have submitted (B) their assignments (C) on time (D)."',options:["Part A","Part B","Part C","No error"],correct:[1],marks:1,negative:.33,estTimeSec:45,solution:{steps:["'Each' is singular and takes a singular verb.","'have submitted' should be 'has submitted'."],concept:"Indefinite pronouns (each, every, either) are singular.",memoryTrick:"EACH and EVERY are lone wolves — always singular."}},{id:"apt-024",module:"aptitude",topic:"Critical Thinking",subtopic:"Logical validity",type:"mcq",difficulty:"medium",companies:["McKinsey","BCG"],tags:["inference"],text:'Premises: "All engineers at the lab know CAD. Ravi works at the lab." Which conclusion is valid?',options:["Ravi knows CAD","Ravi is an engineer","If Ravi is an engineer at the lab, he knows CAD","Everyone who knows CAD is an engineer"],correct:[2],marks:2,negative:.66,estTimeSec:90,solution:{steps:["'Works at the lab' does not imply 'is an engineer' — Ravi could be an accountant.","Only the conditional statement is forced by the premises."],concept:"Valid inference adds no unstated assumptions.",memoryTrick:"Check every conclusion for a smuggled assumption."}},{id:"apt-025",module:"aptitude",topic:"Puzzle Solving",subtopic:"Rates",type:"nat",difficulty:"medium",companies:["Google","Adobe"],tags:["classic puzzle"],text:"If 3 hens lay 3 eggs in 3 days, how many eggs do 12 hens lay in 12 days?",answer:{value:48,tolerance:0},marks:2,negative:0,estTimeSec:90,solution:{steps:["3 hens lay 3 eggs in 3 days ⇒ 1 hen lays 1 egg in 3 days.","1 hen in 12 days lays 4 eggs ⇒ 12 hens lay 48."],concept:"Unitary method with two varying quantities.",commonMistakes:["Answering 12 by pattern-matching the numbers"],memoryTrick:"Reduce to 'one hen, one day' before scaling up."}},{id:"apt-026",module:"aptitude",topic:"Quantitative Aptitude",subtopic:"Boats & Streams",type:"nat",difficulty:"easy",tags:["streams"],text:"A boat's speed in still water is 10 km/h and the stream flows at 2 km/h. How many hours to travel 24 km upstream?",answer:{value:3,tolerance:.01},marks:1,negative:0,estTimeSec:60,solution:{steps:["Upstream speed = 10 − 2 = 8 km/h","Time = 24/8 = 3 h"],concept:"Effective speed against the current.",memoryTrick:"Up subtracts, down adds."}},{id:"apt-027",module:"aptitude",topic:"Quantitative Aptitude",subtopic:"Mixtures",type:"mcq",difficulty:"medium",companies:["TCS-style","Goldman Sachs"],tags:["mixtures"],text:"A 40-litre mixture has milk and water in ratio 3 : 1. After adding 10 litres of water, the new milk : water ratio is:",options:["3 : 2","2 : 1","6 : 5","1 : 1"],correct:[0],marks:2,negative:.66,estTimeSec:90,solution:{steps:["Initially: milk = 30 L, water = 10 L.","Add 10 L water: milk 30, water 20.","Ratio = 30 : 20 = 3 : 2."],concept:"Track absolute quantities, not ratios, through the change.",commonMistakes:["Adding to the ratio terms directly (3 : 1+10)"],memoryTrick:"Convert ratio → litres → back to ratio. Always."}},{id:"apt-028",module:"aptitude",topic:"Quantitative Aptitude",subtopic:"Pipes & Cisterns",type:"nat",difficulty:"medium",tags:["pipes"],text:"Pipe A fills a tank in 6 hours; drain B empties it in 12 hours. With both open, how many hours to fill the tank?",answer:{value:12,tolerance:.05},marks:2,negative:0,estTimeSec:90,solution:{steps:["Net rate = 1/6 − 1/12 = 1/12 tank per hour.","Time = 12 hours."],concept:"Filling and emptying rates subtract.",memoryTrick:"Pipes are just time-and-work with a saboteur."}},{id:"apt-029",module:"aptitude",topic:"Quantitative Aptitude",subtopic:"Simple Interest",type:"nat",difficulty:"easy",tags:["interest"],text:"Find the simple interest (₹) on ₹5,000 at 8% per annum for 3 years.",answer:{value:1200,tolerance:1},marks:1,negative:0,estTimeSec:45,solution:{steps:["SI = PRT/100 = 5000 × 8 × 3/100","SI = ₹1,200"],concept:"Simple interest is linear in time.",formula:"SI = PRT/100"}},{id:"apt-030",module:"aptitude",topic:"Logical Reasoning",subtopic:"Calendar",type:"mcq",difficulty:"medium",tags:["calendar"],text:"If today is Monday, what day of the week will it be 61 days from now?",options:["Friday","Saturday","Sunday","Monday"],correct:[1],marks:1,negative:.33,estTimeSec:60,solution:{steps:["61 mod 7 = 5 (since 56 is a whole number of weeks).","Monday + 5 days = Saturday."],concept:"Day-of-week arithmetic modulo 7.",memoryTrick:"Throw away complete weeks first — only the remainder matters."}},{id:"apt-031",module:"aptitude",topic:"Data Interpretation",subtopic:"Percentages",type:"nat",difficulty:"easy",companies:["BCG","McKinsey"],tags:["quick calculation"],text:"A survey covered two groups: 250 students (30% selected coding) and 150 students (40% selected coding). How many students in total selected coding?",answer:{value:135,tolerance:0},marks:1,negative:0,estTimeSec:60,solution:{steps:["30% of 250 = 75","40% of 150 = 60","Total = 75 + 60 = 135"],concept:"Weighted counts — never average the percentages directly.",commonMistakes:["Taking 35% of 400 = 140 (averaging the rates)"]}},{id:"apt-032",module:"aptitude",topic:"Verbal Ability",subtopic:"Analogies",type:"mcq",difficulty:"easy",tags:["analogy"],text:"PILOT : COCKPIT :: CAPTAIN : ?",options:["Ocean","Bridge","Anchor","Crew"],correct:[1],marks:1,negative:.33,estTimeSec:30,solution:{steps:["A pilot commands from the cockpit; a ship's captain commands from the bridge.","The relation is 'person : their command station'."],concept:"Identify the precise relationship before scanning options.",memoryTrick:"Make a sentence of the pair, then test each option in that sentence."}},{id:"int-001",module:"interview",topic:"Technical Interview",subtopic:"Aerodynamics",type:"mcq",difficulty:"interview",companies:["Airbus","Boeing"],tags:["winglets"],text:'Interviewer: "Why do modern airliners have winglets?" The best core answer is:',options:["They make the aircraft look modern for marketing","They weaken wingtip vortices, reducing induced drag and fuel burn","They increase wing area and hence total lift","They are mainly radio antennas"],correct:[1],marks:2,negative:0,estTimeSec:60,source:"Airbus/Boeing interview classic",solution:{steps:["Pressure leakage around the tip creates vortices, which induce downwash and drag.","Winglets act as a barrier and recover some vortex energy, cutting induced drag ~3-5% in cruise.","Strong answers quantify the fuel saving and mention the span-limit trade-off at gates."],concept:"Induced drag mitigation on finite wings.",memoryTrick:"Winglet = 'fence' against the tip leak."}},{id:"int-002",module:"interview",topic:"Technical Interview",subtopic:"High-speed aerodynamics",type:"mcq",difficulty:"interview",companies:["Boeing","HAL","DRDO"],tags:["swept wings"],text:'"Why are transport aircraft wings swept back?" The primary reason is:',options:["To improve roll rate","To reduce the effective Mach number normal to the leading edge, delaying drag divergence","To shift the CG rearward","To reduce wing weight"],correct:[1],marks:2,negative:0,estTimeSec:60,solution:{steps:["Only the velocity component normal to the leading edge drives compressibility effects.","Sweep Λ reduces it by cos Λ, postponing the transonic drag rise to higher flight Mach numbers.","Mention the costs: lower CLmax, tip-stall tendency, structural weight."],concept:"Simple sweep theory and drag-divergence Mach number.",formula:"M_eff = M·cos Λ",memoryTrick:"The wing only 'feels' the flow crossing it head-on."}},{id:"int-003",module:"interview",topic:"Technical Interview",subtopic:"Transonic design",type:"mcq",difficulty:"interview",companies:["Boeing","DRDO"],tags:["area rule"],text:"The Whitcomb area rule states that to minimize transonic wave drag, an aircraft should have:",options:["Maximum wing thickness at the root","A smooth longitudinal distribution of total cross-sectional area","Equal wing and tail areas","A cylindrical fuselage throughout"],correct:[1],marks:2,negative:0,estTimeSec:60,solution:{steps:["Wave drag near Mach 1 depends on the whole body's area distribution, not components separately.","Hence the classic 'coke-bottle' fuselage waisting where the wing adds area."],concept:"Transonic area ruling.",memoryTrick:"Coke-bottle fuselage = area rule in the metal."}},{id:"int-004",module:"interview",topic:"Technical Interview",subtopic:"Propulsion",type:"mcq",difficulty:"interview",companies:["HAL","Airbus"],tags:["turbofan"],text:'"Why are high-bypass turbofans more fuel-efficient than turbojets at subsonic speeds?"',options:["They burn cooler and hence use less fuel per kg of air","Accelerating a large air mass slightly gives higher propulsive efficiency than a small mass greatly","The fan compresses air more efficiently than a compressor","Bypass air cools the turbine, allowing higher RPM"],correct:[1],marks:2,negative:0,estTimeSec:60,solution:{steps:["For fixed thrust ṁΔV, kinetic-energy loss scales with ΔV² — many kilograms at small ΔV waste less energy.","ηp = 2/(1 + Ve/V₀) → higher as Ve approaches V₀."],concept:"Propulsive efficiency vs specific thrust trade-off.",formula:"ηp = 2/(1 + Ve/V₀)",memoryTrick:"Gentle push on a lot of air beats violent push on a little."}},{id:"int-005",module:"interview",topic:"Technical Interview",subtopic:"Flight envelope",type:"mcq",difficulty:"interview",companies:["Boeing","HAL"],tags:["coffin corner"],text:"\"What is the 'coffin corner' of a high-altitude aircraft?\"",options:["The rear cargo area near the tail","The altitude where stall speed and critical Mach speed converge","The runway corner where crosswind is worst","The point of maximum wing bending"],correct:[1],marks:2,negative:0,estTimeSec:60,solution:{steps:["As altitude rises, true stall speed increases (thin air) while the Mach-buffet limit decreases.","Where they meet, the aircraft is squeezed: fly slower → stall; faster → Mach buffet.","U-2 pilots famously operated within a few knots of both limits."],concept:"High-altitude flight-envelope contraction.",memoryTrick:"Squeezed between stall and shock."}},{id:"int-006",module:"interview",topic:"Technical Interview",subtopic:"Launch vehicles",type:"mcq",difficulty:"interview",companies:["ISRO","DRDO"],tags:["staging"],text:'"Why are rockets built in multiple stages?"',options:["Different fuels must be kept apart","Discarding empty tanks and engines raises the achievable Δv for the same propellant","Single-stage rockets are illegal under space law","Staging reduces aerodynamic heating"],correct:[1],marks:2,negative:0,estTimeSec:60,source:"ISRO interview classic",solution:{steps:["Δv = Ve·ln(m₀/mf): dead structural mass in mf strangles the log term.","Dropping spent stages shrinks mf mid-flight, effectively multiplying mass ratios of each stage.","Great answers note SSTO is marginal with chemical propellants precisely because of this."],concept:"Staging beats the logarithm in the rocket equation.",memoryTrick:"Climbing a mountain, you drop each empty water bottle."}},{id:"int-007",module:"interview",topic:"Technical Interview",subtopic:"Computer networks",type:"mcq",difficulty:"interview",companies:["Google","Microsoft","Uber"],tags:["systems"],text:'"What happens when you type a URL and press Enter?" — the FIRST network step (after cache checks) is:',options:["A TCP three-way handshake","DNS resolution of the hostname to an IP address","TLS certificate exchange","An HTTP GET request"],correct:[1],marks:2,negative:0,estTimeSec:60,source:"Universal SDE interview opener",solution:{steps:["Order: DNS → TCP handshake → TLS handshake → HTTP request → response → render.","You cannot open a TCP connection without an IP address, so DNS must come first."],concept:"Web request lifecycle.",memoryTrick:"'Do The Talking, Human' — DNS, TCP, TLS, HTTP."}},{id:"int-008",module:"interview",topic:"Technical Interview",subtopic:"OOP",type:"mcq",difficulty:"interview",companies:["Amazon","Adobe","Qualcomm"],tags:["polymorphism"],text:"Polymorphism in object-oriented programming means:",options:["One class inheriting from many classes","The same interface invoking different behavior depending on the object's actual type","Hiding data behind private members","Copying methods between classes"],correct:[1],marks:2,negative:0,estTimeSec:60,solution:{steps:["A base-class reference can point to derived objects; virtual dispatch selects the right override at runtime.","Example: Shape.area() resolving to Circle.area() or Square.area().","Distinguish compile-time (overloading) from runtime (overriding) polymorphism."],concept:"Runtime polymorphism via dynamic dispatch.",memoryTrick:"Poly-morph = many forms behind one face."}},{id:"int-009",module:"interview",topic:"Technical Interview",subtopic:"Operating systems",type:"mcq",difficulty:"interview",companies:["NVIDIA","Qualcomm","Microsoft"],tags:["process","thread"],text:"The key difference between a process and a thread is:",options:["Threads run only on single-core CPUs","Threads of one process share its address space; processes have isolated memory","Processes are faster to create than threads","A process cannot contain more than one thread"],correct:[1],marks:2,negative:0,estTimeSec:60,solution:{steps:["A process owns memory, file handles and at least one thread.","Threads share the heap and globals (cheap communication, data-race risk); each has its own stack and registers.","Isolation makes processes safer but IPC costlier."],concept:"OS execution model: isolation vs sharing.",memoryTrick:"Process = house; threads = roommates sharing the kitchen."}},{id:"int-010",module:"interview",topic:"Behavioral",subtopic:"STAR method",type:"mcq",difficulty:"easy",companies:["Amazon","McKinsey"],tags:["star"],text:"In the STAR method for behavioral answers, the four parts are:",options:["Skill, Talent, Ambition, Result","Situation, Task, Action, Result","Story, Timing, Answer, Reflection","Strength, Trouble, Adjustment, Reward"],correct:[1],marks:1,negative:0,estTimeSec:30,solution:{steps:["Situation: set the scene briefly. Task: your specific responsibility.","Action: what YOU did (60% of the answer). Result: quantified outcome + lesson."],concept:"Structured behavioral storytelling.",memoryTrick:"Spend most words on A — interviewers hire for actions, not settings."}},{id:"int-011",module:"interview",topic:"HR",subtopic:"Weakness question",type:"mcq",difficulty:"easy",companies:["Amazon","Tata Technologies"],tags:["hr"],text:'The strongest way to answer "What is your greatest weakness?" is to:',options:["Claim perfectionism as a disguised strength","Name a real, non-fatal weakness plus concrete steps you are taking to improve","Say you have no weaknesses worth mentioning","Redirect the question to your strengths"],correct:[1],marks:1,negative:0,estTimeSec:45,solution:{steps:["Authenticity + self-awareness + a visible improvement plan is what's actually assessed.","Pick a weakness not central to the role (e.g. public speaking for a design role), show progress evidence."],concept:"Self-awareness signaling in HR rounds.",commonMistakes:["'I work too hard' — interviewers hear this daily and discount it"]}},{id:"int-012",module:"interview",topic:"Research Interview",subtopic:"Project presentation",type:"mcq",difficulty:"interview",companies:["ISRO","DRDO","Mercedes-Benz R&D"],tags:["project discussion"],text:'When asked "Walk me through your M.Tech project", the most effective structure is:',options:["Chronological diary of everything you tried","Problem → why it matters → your approach → key result → impact/limitations","List of software tools used, then results","Start with equations to prove depth"],correct:[1],marks:2,negative:0,estTimeSec:60,solution:{steps:["Open with the problem and its significance in one sentence each — hook the interviewer.","Describe the approach at system level, then dive deep only where they probe.","Close with a quantified result and honest limitations — invites the discussion you want."],concept:"Top-down technical storytelling.",memoryTrick:"Newspaper style: headline first, details on demand."}}];function r(e=[]){let t=new Map;for(let e of n)t.set(e.id,e);for(let i of e)t.set(i.id,i);return t}function c(e,t=[]){return[...n,...t].filter(t=>t.module===e)}e.s(["ALL_QUESTIONS",0,n,"MODULE_LABELS",0,{aerospace:"Core Aerospace",coding:"Coding",aptitude:"Aptitude",interview:"Interview Prep"},"buildQuestionMap",0,r,"getQuestionsByIds",0,function(e,t=[]){let i=r(t);return e.map(e=>i.get(e)).filter(e=>!!e)},"questionsForModule",0,c,"topicsForModule",0,function(e,t=[]){return[...new Set(c(e,t).map(e=>e.topic))]}],12854)}]);